What does this component render?

```jsx
function StatusBadge() {
  const status = "active";
  const count = 12;

  return (
    <span className="badge">
      {status}: {count} items
    </span>
  );
}

export default StatusBadge;
```

In this component, which line separates the logic zone from the markup zone?

```jsx
const OrderSummary = () => {
  const items = 3;
  const shipping = items > 2 ? "Free" : "$5.99";
  const message = `You have ${items} items`;

  return (
    <div>
      <p>{message}</p>
      <p>Shipping: {shipping}</p>
    </div>
  );
};
```

What does `export default` do in a React file?

```jsx
function DashboardHeader() {
  return <h1>Dashboard</h1>;
}

function helperFunction() {
  // some internal logic
}

export default DashboardHeader;
```
